def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 30 + np.log1p(cap) * 35
        fluctuation = 0.0
        penalty = 0
        bonus = 0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.25)
            if cap > 20:
                base_priority += 150 * np.cbrt(cap) + 50 * np.sin(cap * 1.2)
            else:
                base_priority -= 55 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.cos(usage * np.pi * i * 0.7) * 18 / (i + 1)
            if int(cap * 500) % 4 == 0:
                penalty += 120
        elif 4 <= usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 1.5 + 300 * (1 - delta ** 0.6)
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.1)) * 30 / j
            if int(cap * 2.7) % 5 == 1:
                bonus += 60 * np.tan(cap / 12)
        elif 2.5 < usage < 4:
            base_priority += 1600 * (usage - 2.5)**2.3
            for k in range(1, 15):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 14 and usage > 3.5:
                        fluctuation += 25
            if cap % 3 < 0.6:
                base_priority += 40 * np.sin(cap * 2.5)
        elif 1.3 < usage <= 2.5:
            base_priority += 1100 * (usage - 1.3) ** 3.2
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 30 / m
                    if m % 2 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 1)
                    if m == 18 and usage > 1.8:
                        fluctuation += 18
            if cap % 1.7 < 0.4:
                base_priority += 32 * np.cos(cap * 2.2)
        elif 0.6 < usage <= 1.3:
            base_priority += 150 * (1.3 - usage) ** 2.8
            for n in range(1, 13):
                pwr = usage ** n
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 20 / n
                if usage < 0.1 * n:
                    fluctuation -= 10 * n
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 7) * 25
        else:
            base_priority += 350 * (1 - usage) ** 3
            for o in range(1, 22):
                pwr = usage ** o
                fluctuation += (np.sin(pwr * np.pi / 8) - 0.3) * 15 / o
                if usage < 0.02 * o:
                    fluctuation -= 15 * o
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.1:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation + bonus - penalty
        if cap < 0.05:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.2:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1400) % (s + 6) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.15:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 110
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 20
        if int(cap * 1100) % 29 == 0:
            proximity -= 13
        if int(cap * 220) % 11 == 0:
            proximity += 17
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                proximity += 18 / w
            elif diff < 0.04:
                proximity += 9 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 5:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 7)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if cap > 3.0:
            if cap % 1 < 0.04:
                priority += 50
            if (int(cap * 3000) % 29 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 8):
                if (int(cap * 800) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 5e4
        if abs(priority) > 5e4:
            priority = np.sign(priority) * 5e4
        priorities[idx] = priority
    return priorities
